example.code:
// Resolved from DI after AddPolymorphicService<IMessageBus>(...) registration:
IServiceRegistry<IMessageBus> registry =
    serviceProvider.GetRequiredService<IServiceRegistry<IMessageBus>>();

IMessageBus defaultBus = registry.Default;
IMessageBus internalBus = registry.Get("Internal");

if (registry.TryGet("Optional") is { } optionalBus)
{
    optionalBus.Publish(message);
}

foreach (string name in registry.Names)
{
    Console.WriteLine(name);
}

if (registry.TryGet("Internal") is { } internalBus)
{
    internalBus.Publish(message);
}

services.AddPolymorphicService<IMessageBus>(configuration, "Messaging", builder =>
{
    builder.AddProvider<KafkaMessageBus, KafkaOptions>("Kafka");
    builder.AddProvider<EmailMessageBus, EmailOptions>("Email");
    builder.AddProvider<NoopMessageBus>("Noop");
});

services.AddPolymorphicService<IMessageBus>(
    configuration,
    sectionPath: "Messaging",
    configure: builder =>
    {
        builder.AddProvider<KafkaMessageBus, KafkaOptions>("Kafka");
        builder.AddProvider<EmailMessageBus, EmailOptions>("Email");
    });

member.summary:
Registers a polymorphic service whose implementation is determined by configuration.
Supports both single-provider and multi-provider (named instances) configuration shapes.


Single-provider (no Providers sub-section):

{ "Provider": "Kafka", "Settings": { ... } }

Multi-provider (with Providers sub-section):

{
  "Default": "Internal",
  "Providers": {
    "Public": { "Provider": "Email", "Settings": { ... } },
    "Internal": { "Provider": "Kafka", "Settings": { ... } }
  }
}

example.code:
services.AddPolymorphicService<IMessageBus>(configuration, "Messaging", builder =>
{
    builder.AddProvider<KafkaMessageBus, KafkaOptions>("Kafka");
});

DateTime scheduledAt = Guard.Against(scheduledAt).InThePast().Value;
DateTime dateOfBirth = Guard.Against(dateOfBirth).InTheFuture().Value;
DateTimeOffset expiresAt = Guard.Against(expiresAt).InThePast().Value;

public Person(string name, int age, DateTime dateOfBirth) {
    Name = Guard.Against(name).NullOrEmpty().LongerThan(100).Value;
    Age  = Guard.Against(age).Negative().GreaterThan(150).Value;
    DateOfBirth = Guard.Against(dateOfBirth).Default().InTheFuture().Value;
}

member.remarks:
The single open generic overload preserves the caller's compile-time type — including its nullability annotation. This means
callers compiled with <Nullable>disable</Nullable> (null-oblivious) get an oblivious carrier and see no nullability warnings;
var-typed locals work for any type — no need to widen List<int> to IEnumerable<int>? or to add a ? just to satisfy a constrained extension method.

example.code:
// Typically created via Guard.Against; rarely instantiated directly.
string name = Guard.Against(rawName).NullOrEmpty().LongerThan(100).Value;
int age = Guard.Against(rawAge).Negative().GreaterThan(150).Value;

// Implicit conversion to T is available at the end of a chain:
string validated = Guard.Against(rawName).NullOrEmpty();

int count = Guard.Against(count).Negative().Value;
int quantity = Guard.Against(quantity).NegativeOrZero().Value;
int divisor = Guard.Against(divisor).Zero().Value;
int offset = Guard.Against(offset).Positive().Value;

string name = Guard.Against(name).Null().Value;
Guid id = Guard.Against(id).Default().Value;
int? count = Guard.Against(count).Null().Negative().Value;

string name = Guard.Against(name).NullOrEmpty().LongerThan(100).Value;
string description = Guard.Against(description).NullOrWhiteSpace().LongerThan(500).Value;
string code = Guard.Against(code).Empty().Value;

// Define a service that takes the clock as a generic type parameter for testability:
public sealed class OrderService<TClock> where TClock : IClock
{
    public Order CreateOrder(string productId) => new Order
    {
        ProductId = productId,
        CreatedAt = TClock.UtcNow
    };
}

// Use SystemClock in production:
var service = new OrderService<SystemClock>();

// Inject a fixed-time clock in tests via a test double:
// var testService = new OrderService<FakeClock>();

public sealed class ProductEntityToDtoMapper : ITypeMapper<ProductEntity, ProductDto>
{
    public ProductDto Map(ProductEntity source) => new()
    {
        Name = source.Name,
        Price = source.Price
    };

    public void Project(ProductEntity source, ProductDto destination)
    {
        destination.Name = source.Name;
        destination.Price = source.Price;
    }
}

member.example:
Given an ProductEntityToDtoMapper that implements ITypeMapper{ProductEntity, ProductDto}, the following maps a ProductEntity instance to a new ProductDto instance:

var mapper = new ProductEntityToDtoMapper();
var theDto = mapper.Map(productEntity);

Creating a type mapper for a source/destination pair is as simple as implementing ITypeMapper{TSource, TDestination}:

public class ProductEntityToDtoMapper : ITypeMapper<ProductEntity, ProductDto>
{
  public ProductDto Map(ProductEntity source)
  {
    return new ProductDto {
        Name = source.Name,
        Price = source.Price
    };
  }
  public void Project(ProductEntity source, ProductDto destination)
  {
    destination.Name = source.Name;
    destination.Price = source.Price;
  }
}

Given an ProductEntityToDtoMapper that implements ITypeMapper{ProductEntity, ProductDto}, the following projects a ProductEntity instance onto an existing ProductDto instance:

var mapper = new ProductEntityToDtoMapper();
mapper.Project(productEntity, existingProductDto);

Implementing the Project method is optional; if not implemented, the TypeMappingService will fall back to mapping to a new instance and copying over the values via reflection:

public class ProductEntityToDtoMapper : ITypeMapper<ProductEntity, ProductDto>
{
    public void Project(ProductEntity source, ProductDto destination) {
        destination.Name = source.Name;
        destination.Price = source.Price;
    }
}

example.code:
ITypeMappingService mapping = serviceProvider.GetRequiredService<ITypeMappingService>();

if (mapping.HasMapper<ProductEntity, ProductDto>())
{
    ProductDto dto = mapping.Map<ProductEntity, ProductDto>(entity);
    List<ProductDto> dtos = mapping.MapToList<ProductEntity, ProductDto>(entities);
}

member.example:
Given a registered mapper for ProductEntity → ProductDto, the following returns :

mappingService.HasMapper<ProductEntity, ProductDto>();
mappingService.HasMapper<SpecialProductEntity, ProductDto>();

Given a registered mapper for ProductEntity → ProductDto, the following returns the mapper instance:

var mapper = mappingService.GetMapper<ProductEntity, ProductDto>();
var theDto = mapper.Map(productEntity);

Given a registered mapper for ProductEntity → ProductDto, the following lazily maps a sequence of ProductEntity instances to ProductDto instances:

var dtos = mappingService.MapCollection<ProductEntity, ProductDto>(productEntities);
foreach (var dto in dtos)         /// {
    Console.WriteLine(dto.Name);
}

