    .Register(new ProductEntityToDtoMapper())
    .RegisterFromAssembly(typeof(UserEntityToDtoMapper).Assembly);

ProductDto dto = service.Map<ProductEntity, ProductDto>(entity);
List<ProductDto> dtos = service.MapToList<ProductEntity, ProductDto>(entities);

var service = new TypeMappingService(
    new ProductEntityToDtoMapper(),
    new UserEntityToDtoMapper());

var mappingService = new TypeMappingService()
    .Register(new UserEntityToDtoMapper())
    .Register(new ProductEntityToDtoMapper());

var mappingService = new TypeMappingService();
mappingService.RegisterInstance(new UserEntityToDtoMapper());
mappingService.RegisterInstance(new ProductEntityToDtoMapper());

services
    .AddTypeMappersFromAssembly(typeof(ProductEntityToDtoMapper).Assembly)
    .AddTypeMapping();

// Resolved at the layer boundary:
var mapping = serviceProvider.GetRequiredService<ITypeMappingService>();
ProductDto dto = mapping.Map<ProductEntity, ProductDto>(entity);

services.AddTypeMapping(svc =>
{
    svc.Register(new ProductEntityToDtoMapper(), overwrite: true);
});

services.AddTypeMappersFromAssemblies(new[]
{
    typeof(ProductEntityToDtoMapper).Assembly,
    typeof(UserEntityToDtoMapper).Assembly
});

var inclusive = new Range<int>(1, 10);
inclusive.IsInRange(5);  // true
inclusive.IsInRange(10); // true

var halfOpen = new Range<int>(1, 10, RangeType.ExclusiveEnd);
halfOpen.IsInRange(10);  // false

var halfOpen = new Range<int>(1, 10, RangeType.ExclusiveEnd);
bool atEnd = halfOpen.IsInRange(10); // false — end is excluded
bool beforeEnd = halfOpen.IsInRange(9); // true

var inclusive = new Range<int>(1, 10, RangeType.Inclusive);
inclusive.IsInRange(1);  // true
inclusive.IsInRange(10); // true

var exclusive = new Range<int>(1, 10, RangeType.Exclusive);
exclusive.IsInRange(1);  // false
exclusive.IsInRange(10); // false

public sealed class TimeoutError : Error
{
    public TimeoutError(TimeSpan elapsed)
    {
        Code = "TIMEOUT";
        Message = $"Operation timed out after {elapsed.TotalSeconds:F1}s.";
    }
}

Result result = Result.Failure(new TimeoutError(TimeSpan.FromSeconds(30)));

try { /* call third-party API */ }
catch (Exception ex)
{
    return Result.Failure(new RuntimeExceptionError(ex));
}

var error = new ValidationError(
    propertyName: nameof(Order.Quantity),
    message: "Quantity must be greater than zero.",
    attemptedValue: "-1");
Result result = Result.Failure(error);

// Void operation — only success/failure matters.
Result ok = Result.Success();
Result bad = Result.Failure(new NotFoundError("Order not found."));

if (bad.IsFailure())
{
    foreach (var error in bad.Errors)
        logger.LogWarning("{Code}: {Message}", error.Code, error.Message);
}

// Typical handler that avoids try/catch for expected failures.
public Result DeleteOrder(Guid id)
{
    var order = _repository.Find(id);
    if (order is null)
        return Result.Failure(new NotFoundError($"Order {id} not found."));

    _repository.Delete(order);
    return Result.Success();
}

var result = new Result();
if (result.IsSuccess()) {
    // Handle success
}

public class MyCustomResult : Result
{
 public override bool IsSuccess() {
     return Errors.Count == 0 || Errors.Contains(e => e.GetType() != typeof(MyErrorThatCanBeIgnored));
 }
}

var result = new Result();
if (result.IsFailure()) {
    // Handle failure
}

// Handler that returns a value without throwing for expected failures.
public Result<Order> GetOrder(Guid id)
{
    var order = _repository.Find(id);
    if (order is null)
        return Result<Order>.Failure(new NotFoundError($"Order {id} not found."));

    return Result<Order>.Success(order);
}

// Caller inspects the outcome without a try/catch.
var result = GetOrder(id);
if (result.IsSuccess())
    Process(result.Value!);
else
    foreach (var error in result.Errors)
        logger.LogWarning("{Code}: {Message}", error.Code, error.Message);

